diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..c6c4027232d0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3326,6 +3326,20 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
     }
     break;
   case Instruction::Add: {
+    // (zext i1 A) + (zext i1 B) == 1 --> xor A, B
+    // (zext i1 A) + (zext i1 B) != 1 --> A == B
+    if (C.isOne() && BO->hasOneUse()) {
+      Value *A, *B;
+      if (match(BOp0, m_ZExt(m_Value(A))) &&
+          match(BOp1, m_ZExt(m_Value(B))) &&
+          A->getType()->isIntOrIntVectorTy(1) &&
+          B->getType()->isIntOrIntVectorTy(1)) {
+        if (Pred == ICmpInst::ICMP_EQ)
+          return BinaryOperator::CreateXor(A, B);
+        else // ICMP_NE
+          return new ICmpInst(ICmpInst::ICMP_EQ, A, B);
+      }
+    }
     // (A + C2) == C --> A == (C - C2)
     // (A + C2) != C --> A != (C - C2)
     // TODO: Remove the one-use limitation? See discussion in D58633.

